#include <iostream>
#include <memory>
#include <utility>

class Token {
    std::unique_ptr<int> value_;
public:
    explicit Token(int value) : value_(std::make_unique<int>(value)) {}
    Token(Token&& other) noexcept : value_(std::move(other.value_)) {}
    Token(const Token&) = delete;
    Token& operator=(const Token&) = delete;
    bool empty() const { return !value_; }
    int value() const { return *value_; }
};

int main() {
    int value{};
    if (!(std::cin >> value)) return 1;
    Token source(value);
    Token destination(std::move(source));
    std::cout << (source.empty() ? "empty" : "owned") << ' ' << destination.value() << '\n';
}
